/// Register all model dependencies for hierarchical sync ordering
void registerModelDependencies() {
  // Contact depends on User via userId
  DependencyResolver.registerDependency('Contact', 'User');
  // Post depends on User via userId
  DependencyResolver.registerDependency('Post', 'User');
  // LocalNote depends on User via ownerId
  DependencyResolver.registerDependency('LocalNote', 'User');
  // IndexingTestProduct depends on IndexingTestCategory via categoryId
  DependencyResolver.registerDependency(
      'IndexingTestProduct', 'IndexingTestCategory');
  // InvalidProduct depends on IndexingTestCategory via categoryId
  DependencyResolver.registerDependency(
      'InvalidProduct', 'IndexingTestCategory');
  // ServerChildModel depends on ServerParentModel via parentId
  DependencyResolver.registerDependency(
      'ServerChildModel', 'ServerParentModel');
  // Department depends on Company via companyId
  DependencyResolver.registerDependency('Department', 'Company');
  // Todo depends on User via userId
  DependencyResolver.registerDependency('Todo', 'User');
  // Project depends on User via ownerId
  DependencyResolver.registerDependency('Project', 'User');
  // Project depends on Category via categoryId
  DependencyResolver.registerDependency('Project', 'Category');
  // Company depends on Department via departmentId
  DependencyResolver.registerDependency('Company', 'Department');
}

/// Initialize the synced storage system
/// This function should be accessible from background isolates
@pragma('vm:entry-point')
void initializeSynquillStorage(GeneratedDatabase database) {
  // Set up global database access
  DatabaseProvider.setInstance(database);

  // Register all repository factories
  registerAllRepositories();

  // Register model dependencies for hierarchical sync
  registerModelDependencies();

  // Register model relations (cascade delete and foreign keys)
  registerModelRelations();
}

